import{_ as l,o as i,c as n,a2 as s}from"./chunks/framework.BnBoz4Zl.js";const u=JSON.parse('{"title":"第 13 章 安全远程协作与故障排查","description":"远程入口适合查看状态、补充指令和确认低风险步骤，不适合绕过公司终端管理或把重要操作变成无人值守。 ::: warning 使用边界 仅使用公司批准的账号、设备、网络和远程方式。涉及文件外发、系统写入、删除覆盖、审批和账号权限的操作，必须回到受控环境并由有权限人员确认。 :::","frontmatter":{},"headers":[],"relativePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 13 章 远程控制你的电脑，不用发愁不在电脑前/index.md","filePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 13 章 远程控制你的电脑，不用发愁不在电脑前/index.md","lastUpdated":1784100816000}'),e={name:"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 13 章 远程控制你的电脑，不用发愁不在电脑前/index.md"};function t(o,a,r,p,h,d){return i(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="第-13-章-安全远程协作与故障排查" tabindex="-1">第 13 章 安全远程协作与故障排查 <a class="header-anchor" href="#第-13-章-安全远程协作与故障排查" aria-label="Permalink to &quot;第 13 章 安全远程协作与故障排查&quot;">​</a></h1><p>远程入口适合查看状态、补充指令和确认低风险步骤，不适合绕过公司终端管理或把重要操作变成无人值守。</p><div class="warning custom-block"><p class="custom-block-title">使用边界</p><p>仅使用公司批准的账号、设备、网络和远程方式。涉及文件外发、系统写入、删除覆盖、审批和账号权限的操作，必须回到受控环境并由有权限人员确认。</p></div><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>离开电脑后查看任务是否完成。</li><li>补充非敏感说明或确认一个低风险步骤。</li><li>读取脱敏输出摘要和错误信息。</li><li>远程停止异常任务并保留日志。</li></ul><h2 id="任务目标" tabindex="-1">任务目标 <a class="header-anchor" href="#任务目标" aria-label="Permalink to &quot;任务目标&quot;">​</a></h2><p>让远程操作做到身份可确认、权限最小化、范围可限制、过程可追踪、异常可停止。</p><h2 id="输入材料" tabindex="-1">输入材料 <a class="header-anchor" href="#输入材料" aria-label="Permalink to &quot;输入材料&quot;">​</a></h2><ul><li>经批准的远程入口和账号。</li><li>指定的工作目录、允许动作和禁止动作。</li><li>任务负责人、确认人和停止条件。</li><li>日志位置与恢复方式。</li></ul><h2 id="执行步骤" tabindex="-1">执行步骤 <a class="header-anchor" href="#执行步骤" aria-label="Permalink to &quot;执行步骤&quot;">​</a></h2><ol><li><strong>本地准备</strong>：先在电脑前测试登录、目录和最小权限。</li><li><strong>限制范围</strong>：只开放当前任务需要的目录和工具。</li><li><strong>先做小样本</strong>：用脱敏文件验证读取、处理和输出路径。</li><li><strong>远程只做必要动作</strong>：优先查看、暂停和确认，不远程扩大权限。</li><li><strong>分层排查</strong>：依次检查设备在线、网络、账号、权限、工作目录、进程和输出日志。</li><li><strong>完成后收口</strong>：退出会话、关闭临时权限并核对输出。</li></ol><h2 id="合成示例" tabindex="-1">合成示例 <a class="header-anchor" href="#合成示例" aria-label="Permalink to &quot;合成示例&quot;">​</a></h2><p>一项文档转换任务运行时间较长。远程端只查看进度和错误摘要；如果输出目录异常，则停止任务，回到电脑前检查路径，而不是远程授予整个磁盘访问权限。</p><h3 id="可复制任务模板" tabindex="-1">可复制任务模板 <a class="header-anchor" href="#可复制任务模板" aria-label="Permalink to &quot;可复制任务模板&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请在本次远程任务中遵守以下边界：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>工作目录：{目录}</span></span>
<span class="line"><span>允许动作：{查看状态/读取指定文件/生成草稿/停止任务}</span></span>
<span class="line"><span>禁止动作：外发、删除、覆盖、审批、扩大权限、访问其他目录</span></span>
<span class="line"><span>停止条件：{错误次数/路径异常/敏感信息/权限不足}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每一步先报告当前状态、准备执行的动作和影响范围；</span></span>
<span class="line"><span>遇到权限、网络或目录问题时停止，不要尝试绕过安全策略；</span></span>
<span class="line"><span>结束后输出操作日志、结果位置和未完成事项。</span></span></code></pre></div><h2 id="人工确认点" tabindex="-1">人工确认点 <a class="header-anchor" href="#人工确认点" aria-label="Permalink to &quot;人工确认点&quot;">​</a></h2><ul><li>入口、账号和设备是否经过批准。</li><li>是否只开放了当前任务所需权限。</li><li>输出是否可以通过远程渠道查看。</li><li>异常时是否应该停止并转为本地处理。</li></ul><h2 id="输出物与验收标准" tabindex="-1">输出物与验收标准 <a class="header-anchor" href="#输出物与验收标准" aria-label="Permalink to &quot;输出物与验收标准&quot;">​</a></h2><ul><li>状态报告包含任务、进度、错误和下一步。</li><li>操作日志能说明何时、由谁、做了什么。</li><li>临时权限已关闭，没有遗留高权限会话。</li><li>失败原因定位到设备、网络、账号、权限、路径或任务层。</li></ul><h2 id="常见弯路与可复用资产" tabindex="-1">常见弯路与可复用资产 <a class="header-anchor" href="#常见弯路与可复用资产" aria-label="Permalink to &quot;常见弯路与可复用资产&quot;">​</a></h2><ul><li>网络不通时反复重装应用，通常会掩盖真实问题。按层排查。</li><li>为了省事开放全部磁盘权限，扩大了误操作范围。坚持最小权限。</li><li>任务没有输出就判断失败，应同时检查进程、日志和目标目录。</li><li>可复用远程任务边界卡、分层排查表和结束检查表。</li></ul>`,21)])])}const b=l(e,[["render",t]]);export{u as __pageData,b as default};
